import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";

const BusMap = () => {
  const [buses, setBuses] = useState([]);

  useEffect(() => {
    const ws = new WebSocket("ws://localhost:8000/ws/buses");

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        const busArray = Object.values(data);
        setBuses(busArray);
      } catch (err) {
        console.error("WebSocket data parse error:", err);
      }
    };

    ws.onclose = () => {
      console.log("WebSocket closed, reconnecting in 5s...");
      setTimeout(() => window.location.reload(), 5000);
    };

    return () => ws.close();
  }, []);

  // Choose marker color based on bus status
  const getColor = (status) => {
    if (status === "Running") return "green";
    if (status === "Ghost") return "red";
    if (status === "Anomaly") return "yellow";
    return "blue"; // fallback
  };

  return (
    <div style={{ height: "100vh", width: "100%" }}>
      <MapContainer
        center={[40.7128, -74.006]} // NYC center
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        {/* Plain white basemap */}
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
          attribution="&copy; Stadia Maps, &copy; OpenMapTiles &copy; OpenStreetMap contributors"
        />

        {buses.map((bus) => (
          <CircleMarker
            key={bus.id}
            center={[bus.lat, bus.lon]}
            radius={8}
            pathOptions={{
              color: getColor(bus.status),
              fillColor: getColor(bus.status),
              fillOpacity: 0.9,
            }}
          >
            <Popup>
              🚌 <b>Bus {bus.id}</b> <br />
              Route: {bus.route} <br />
              Speed: {bus.speed.toFixed(1)} mph <br />
              Status: {bus.status}
            </Popup>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
};

export default BusMap;
